function normalizeCurrencyCode(value) {
  if (!value) return '';
  const v = String(value).toUpperCase();
  if (v === 'JPY' || v === '392') return '392'; // JPY
  if (v === 'USD' || v === '840') return '840'; // USD
  if (v === 'THB' || v === '764') return '764'; // THB
  if (v === 'KRW' || v === 'KOR' || v === '410') return '410'; // KRW(KOR)
  return value;
}

// ===== 로그 날짜 필터 공통(방콕 기준) =====
const BANGKOK_OFFSET_MS = 7 * 60 * 60 * 1000; // Asia/Bangkok = UTC+7 (DST 없음)
function toYmdUTC(d) {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}
function getBangkokYmdFromIso(iso) {
  if (!iso) return '';
  const t = Date.parse(String(iso));
  if (!t || Number.isNaN(t)) return '';
  // 방콕 자정 기준 비교를 위해 ms에 오프셋을 더한 뒤 UTC 날짜를 사용
  const bang = new Date(t + BANGKOK_OFFSET_MS);
  return toYmdUTC(bang);
}
function getBangkokTodayYmd() {
  return toYmdUTC(new Date(Date.now() + BANGKOK_OFFSET_MS));
}
function calcBangkokPresetRange(preset) {
  const p = String(preset || '').toString().trim();
  if (!p) return null;
  const nowBang = new Date(Date.now() + BANGKOK_OFFSET_MS);
  const base = new Date(Date.UTC(nowBang.getUTCFullYear(), nowBang.getUTCMonth(), nowBang.getUTCDate()));
  const todayYmd = toYmdUTC(base);

  const dayOfWeek = base.getUTCDay(); // 0=일요일
  const mondayDiff = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;

  const ymd = (d) => toYmdUTC(new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate())));

  if (p === 'today') return { startDate: todayYmd, endDate: todayYmd };
  if (p === 'yesterday') {
    const d = new Date(base);
    d.setUTCDate(d.getUTCDate() - 1);
    const s = ymd(d);
    return { startDate: s, endDate: s };
  }
  if (p === 'this_week') {
    const start = new Date(base);
    start.setUTCDate(start.getUTCDate() + mondayDiff);
    const end = new Date(start);
    end.setUTCDate(end.getUTCDate() + 6);
    return { startDate: ymd(start), endDate: ymd(end) };
  }
  if (p === 'last_week') {
    const end = new Date(base);
    end.setUTCDate(end.getUTCDate() + mondayDiff - 1);
    const start = new Date(end);
    start.setUTCDate(start.getUTCDate() - 6);
    return { startDate: ymd(start), endDate: ymd(end) };
  }
  if (p === 'this_month') {
    const start = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth(), 1));
    const end = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth() + 1, 0));
    return { startDate: ymd(start), endDate: ymd(end) };
  }
  if (p === 'last_month') {
    const start = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth() - 1, 1));
    const end = new Date(Date.UTC(base.getUTCFullYear(), base.getUTCMonth(), 0));
    return { startDate: ymd(start), endDate: ymd(end) };
  }
  return null;
}

function parseLogDateRangeFromQuery(q) {
  const startDateQ = (q.startDate || '').toString().trim();
  const endDateQ = (q.endDate || '').toString().trim();
  const presetQ = (q.preset || '').toString().trim();
  let startDate = startDateQ;
  let endDate = endDateQ;
  if (!startDate && !endDate && presetQ) {
    const r = calcBangkokPresetRange(presetQ);
    if (r) {
      startDate = r.startDate;
      endDate = r.endDate;
    }
  }
  return { startDate, endDate, preset: presetQ };
}

/** 피지·전산 결과/노티 로그 공통: 전체 열 텍스트 검색어 (logSearch 우선, 구 txId 호환) */
function adminLogFullSearchRaw(q) {
  const ls = (q && q.logSearch != null ? String(q.logSearch) : '').trim();
  if (ls) return ls;
  return (q && q.txId != null ? String(q.txId) : '').trim();
}

/** 검색어와 일치하는 구간만 esc 후 노란 배경 mark (대소문자 무시). 검색어 없으면 전체 esc만 */
function highlightLogSearchHtml(raw, searchRaw, escFn) {
  const q = String(searchRaw || '').trim();
  if (!q) return escFn(raw);
  let escRe;
  try {
    escRe = q.replace(/[\\^$.*+?()[\]{}|]/g, '\\$&');
  } catch {
    return escFn(raw);
  }
  let re;
  try {
    re = new RegExp('(' + escRe + ')', 'gi');
  } catch {
    return escFn(raw);
  }
  const str = String(raw ?? '');
  const parts = str.split(re);
  return parts
    .map((part, i) => {
      if (!part) return '';
      if (i % 2 === 1) return '<mark class="log-search-hit">' + escFn(part) + '</mark>';
      return escFn(part);
    })
    .join('');
}

/** 노티거래내역 Route 검색용: 가맹점 route → 본문 RouteNo → routeKey 숫자 */
function notiTransactionRouteNoForSearch(log, body, merchant) {
  const routeFromBody =
    body.RouteNo != null && String(body.RouteNo).trim() !== ''
      ? String(body.RouteNo).trim()
      : body.routeNo != null && String(body.routeNo).trim() !== ''
        ? String(body.routeNo).trim()
        : '';
  if (merchant && merchant.routeNo != null && String(merchant.routeNo).trim() !== '') {
    return String(merchant.routeNo).trim();
  }
  if (routeFromBody) return routeFromBody;
  return (String(log.routeKey || '').match(/\d+/) || [])[0] || '';
}

/** ROUTE 필드 검색 시 부분 일치 금지 (예: "1"이 "10"에 걸리지 않음) */
function routeNoSearchExactMatch(routeVal, wantRaw) {
  const w = String(wantRaw || '').trim();
  const r = String(routeVal || '').trim();
  if (!w) return true;
  if (r === w) return true;
  const nw = parseInt(w, 10);
  const nr = parseInt(r, 10);
  if (!Number.isNaN(nw) && !Number.isNaN(nr) && String(nw) === w && String(nr) === r && nw === nr) return true;
  return false;
}

function notiHaystackPgResultLog(log, locale, logPg) {
  const body = parseNotiBody(log);
  const dt = formatDateAndTimeTHJP(log.receivedAtIso || log.receivedAt);
  const routeNo = (log.routeKey && (log.routeKey.match(/\/(\d+)$/) || [null, log.routeKey])[1]) || log.routeKey || '';
  const envLabel = (log.env && String(log.env).toLowerCase()) === 'sandbox' ? 'sandbox' : 'live';
  const relayStatus = String(log.relayStatus || '');
  const failReason = String(log.relayFailReason || '');
  const txId = String(body.TransactionId != null ? body.TransactionId : (body.transactionId != null ? body.transactionId : ''));
  const orderNo = String(body.OrderNo != null ? body.OrderNo : (body.orderNo != null ? body.orderNo : ''));
  const amtRaw = body.Amount != null ? body.Amount : (body.amount != null ? body.amount : '');
  const amtDisplay = amtRaw !== '' && amtRaw != null ? String(formatAmountWithSeparator(amtRaw)) : '';
  const currency = String(formatCurrencyForDisplay(body.Currency || body.currency) || body.Currency || body.currency || '');
  const pgK = logPg === 'jpay' ? 'jpay' : 'chillpay';
  const amtRawIcopay = getNotiBodyAmountRawForIcopay(body, pgK);
  let icopayStr = '';
  if (amtRawIcopay !== '' && amtRawIcopay != null) {
    const ic = computeIcopayAmount(amtRawIcopay, body.Currency ?? body.currency, pgK);
    if (Number.isFinite(ic)) icopayStr = String(formatAmountWithSeparator(ic));
  }
  const relayLabel =
    relayStatus === 'ok'
      ? t(locale, 'status_ok')
      : relayStatus === 'fail'
        ? t(locale, 'status_fail')
        : relayStatus === 'skip'
          ? t(locale, 'status_skip')
          : relayStatus;
  const resendKindVal = isCancelNotiBody(body) ? 'cancel' : 'payment';
  const notiKindLabel = resendKindVal === 'cancel' ? t(locale, 'status_cancel') : t(locale, 'status_payment');
  let bodyJson = '';
  try {
    bodyJson = JSON.stringify(body);
  } catch (_) {
    bodyJson = '';
  }
  const jpayMid = String(jpayMidLabelForLog(log) || '');
  return [
    dt.date,
    dt.timeTh,
    dt.timeJp,
    routeNo,
    envLabel,
    log.merchantId,
    txId,
    orderNo,
    amtDisplay,
    currency,
    icopayStr,
    relayStatus,
    relayLabel,
    failReason,
    notiKindLabel,
    jpayMid,
    log.routeKey || '',
    bodyJson,
  ]
    .join(' ')
    .toLowerCase();
}

function notiHaystackPgNotiLog(log, locale) {
  const dt = formatDateAndTimeTHJP(log.receivedAtIso || log.receivedAt);
  const body = log.body && typeof log.body === 'object' ? log.body : (typeof log.body === 'string' ? (() => { try { return JSON.parse(log.body); } catch { return {}; } })() : {});
  let jsonCallback = log.kind === 'callback' ? JSON.stringify(log.body, null, 2) : '';
  let jsonResult = log.kind === 'result' ? JSON.stringify(log.body, null, 2) : '';
  if (log.kind === 'callback' && jsonCallback === '{}' && log.rawBody) jsonCallback = String(log.rawBody);
  if (log.kind === 'result' && jsonResult === '{}' && log.rawBody) jsonResult = String(log.rawBody);
  const relayStatus = log.relayStatus || '';
  const relayHasTarget = !!log.targetUrl;
  const relayLabel =
    relayStatus === 'ok'
      ? t(locale, 'status_ok')
      : relayStatus === 'fail'
        ? t(locale, 'status_fail')
        : relayStatus === 'skip' && !relayHasTarget
          ? t(locale, 'status_noti_none')
          : relayStatus === 'skip'
            ? t(locale, 'status_skip')
            : relayStatus;
  let bodyJson = '';
  try {
    bodyJson = JSON.stringify(body);
  } catch (_) {
    bodyJson = '';
  }
  const resendKindValHay = isCancelNotiBody(body) ? 'cancel' : 'payment';
  const notiKindLabelHay =
    resendKindValHay === 'cancel' ? t(locale, 'status_cancel') : t(locale, 'status_payment');
  return [
    dt.date,
    dt.timeTh,
    dt.timeJp,
    log.routeKey,
    log.merchantId,
    relayStatus,
    relayLabel,
    log.relayFailReason || '',
    jsonCallback,
    jsonResult,
    notiKindLabelHay,
    log.targetUrl || '',
    jpayMidLabelForLog(log) || '',
    bodyJson,
  ]
    .join(' ')
    .toLowerCase();
}

function internalHaystackAdminLog(log, locale) {
  const dt = formatDateAndTimeTHJP(log.storedAtIso || log.storedAt);
  const payload = log.payload || {};
  const displayPayload = jpayInternalLogDisplayPayload(log);
  const jsonHeader = Object.keys(displayPayload).join(', ');
  const jsonValue = JSON.stringify(displayPayload, null, 2);
  const internalStatus = log.internalDeliveryStatus || '';
  const internalLabel =
    internalStatus === 'ok'
      ? t(locale, 'status_ok')
      : internalStatus === 'fail'
        ? t(locale, 'status_fail')
        : internalStatus === 'skip'
          ? t(locale, 'status_skip')
          : internalStatus;
  const internalTargetName = getInternalTargetName(log.internalTargetId);
  let payloadJson = '';
  try {
    payloadJson = JSON.stringify(payload);
  } catch (_) {
    payloadJson = '';
  }
  return [
    dt.date,
    dt.timeTh,
    dt.timeJp,
    internalTargetName,
    internalLabel,
    internalStatus,
    jsonHeader,
    jsonValue,
    log.merchantId,
    log.routeNo,
    log.internalTargetId,
    payloadJson,
  ]
    .join(' ')
    .toLowerCase();
}

function internalResultHaystackLog(log, locale, envLabel) {
  const payload = log.payload || {};
  const dt = formatDateAndTimeTHJP(log.storedAtIso || log.storedAt);
  const txId = String(payload.TransactionId != null ? payload.TransactionId : (payload.transactionId != null ? payload.transactionId : ''));
  const payStatus = payload.PaymentStatus != null ? payload.PaymentStatus : '';
  const statusDesc =
    payStatus === '2' || payStatus === 2
      ? t(locale, 'status_void')
      : payStatus === '9' || payStatus === 9
        ? t(locale, 'status_refund')
        : payStatus === '1' || payStatus === 1
          ? t(locale, 'status_payment')
          : String(payStatus);
  const internalStatus = log.internalDeliveryStatus || '';
  const deliveryLabel =
    internalStatus === 'ok'
      ? t(locale, 'status_ok')
      : internalStatus === 'fail'
        ? t(locale, 'status_fail')
        : internalStatus === 'skip'
          ? t(locale, 'status_skip')
          : internalStatus;
  const internalTargetName = getInternalTargetName(log.internalTargetId);
  let payloadJson = '';
  try {
    payloadJson = JSON.stringify(payload);
  } catch (_) {
    payloadJson = '';
  }
  return [
    dt.date,
    dt.timeTh,
    dt.timeJp,
    txId,
    String(payStatus),
    statusDesc,
    String(log.routeNo || ''),
    internalTargetName,
    envLabel,
    log.merchantId,
    internalStatus,
    deliveryLabel,
    payloadJson,
  ]
    .join(' ')
    .toLowerCase();
}

/** 로그분석·종합거래 목록 공통 한 번에 보기 (파일 상단에 두어 모든 핸들러에서 사용) */
const CR_LIST_PER_PAGE_DEFAULT = 100;
const CR_LIST_PER_PAGE_CHOICES = [100, 200, 300, 400, 500];
const CR_LIST_PER_PAGE_MAX = Math.max(...CR_LIST_PER_PAGE_CHOICES);

function parseAllowedPerPage(qPerPage) {
  const n = parseInt(qPerPage, 10);
  return CR_LIST_PER_PAGE_CHOICES.includes(n) ? n : CR_LIST_PER_PAGE_DEFAULT;
}

function buildQueryString(obj) {
  const parts = [];
  Object.keys(obj || {}).forEach((k) => {
    const v = obj[k];
    if (v === undefined || v === null) return;
    if (typeof v === 'string' && v.trim() === '') return;
    parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  });
  return parts.join('&');
}

/** 무효·환불·강제환불 툴바 period 값 정규화(로그 화면의 this_week 등과 혼용 시 대응) */
function normalizeCrToolbarPeriod(p) {
  const s = String(p || '').trim();
  const map = {
    this_week: 'thisWeek',
    last_week: 'lastWeek',
    this_month: 'thisMonth',
    last_month: 'lastMonth',
  };
  return map[s] || s;
}

/** 로그/결과 GET 필터: 입력·검색 초기화 ｜ 시작·종료일·적용 ｜ 기간 프리셋 */
function renderAdminLogFilterBar(locale, cfg) {
  const esc = cfg.esc;
  const escAttr = (v) => String(esc(v ?? '')).replace(/"/g, '&quot;');
  const {
    logSearchRaw,
    startDateStr,
    endDateStr,
    presetUsed,
    presetHref,
    resetHref,
  } = cfg;
  const sep = '<span class="admin-log-filter-sep" aria-hidden="true">｜</span>';
  const presetPairs = [
    ['today', t(locale, 'tx_filter_today')],
    ['yesterday', t(locale, 'tx_filter_yesterday')],
    ['this_week', t(locale, 'tx_filter_this_week')],
    ['last_week', t(locale, 'tx_filter_last_week')],
    ['this_month', t(locale, 'tx_filter_this_month')],
    ['last_month', t(locale, 'tx_filter_last_month')],
  ];
  const presetsHtml = presetPairs
    .map(([key, label]) => {
      const active = presetUsed === key;
      const bg = active ? '#2563eb' : '#e5e7eb';
      const fg = active ? '#fff' : '#374151';
      return (
        '<a href="' +
        presetHref(key) +
        '" style="padding:4px 8px;font-size:12px;border-radius:6px;text-decoration:none;background:' +
        bg +
        ';color:' +
        fg +
        ';">' +
        esc(label) +
        '</a>'
      );
    })
    .join('');
  return (
    '<div class="admin-log-filter-bar">' +
    '<div class="admin-log-filter-seg">' +
    '<input type="text" name="logSearch" value="' +
    escAttr(logSearchRaw) +
    '" placeholder="' +
    escAttr(t(locale, 'admin_log_search_placeholder')) +
    '" class="admin-log-filter-input" />' +
    '<a href="' +
    resetHref +
    '" class="admin-log-filter-reset">' +
    esc(t(locale, 'common_search_reset')) +
    '</a>' +
    '</div>' +
    sep +
    '<div class="admin-log-filter-seg">' +
    '<input type="date" name="startDate" value="' +
    escAttr(startDateStr) +
    '" aria-label="' +
    escAttr(t(locale, 'logs_filter_start_date')) +
    '" class="admin-log-filter-date" />' +
    '<input type="date" name="endDate" value="' +
    escAttr(endDateStr) +
    '" aria-label="' +
    escAttr(t(locale, 'logs_filter_end_date')) +
    '" class="admin-log-filter-date" />' +
    '<button type="submit" class="admin-log-filter-apply">' +
    esc(t(locale, 'tx_apply')) +
    '</button>' +
    '</div>' +
    sep +
    '<div class="admin-log-filter-seg">' +
    presetsHtml +
    '</div>' +
    '</div>'
  );
}

// 태국 시간(Asia/Bangkok) 문자열 생성 (노티 로그용)
function getThailandNowString() {
  return new Date().toLocaleString('th-TH', {
    timeZone: 'Asia/Bangkok',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });
}

// 4개 시간대(태국/일본/싱가포르/미국) 포맷 (로그 표시용)
function formatTimeMultiTZ(isoString) {
  if (!isoString) return '-';
  const d = new Date(isoString);
  if (Number.isNaN(d.getTime())) return '-';
  const opts = {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  };
  // 태국은 YYYY-MM-DD HH:mm:ss 형식 유지
  const th = d.toLocaleString('en-CA', { ...opts, timeZone: 'Asia/Bangkok' }).replace(',', '');
  // JP/SG/US 는 한국식 연·월·일 표현(예: 2026. 3. 13. 09:53:50)으로 표시
  const jp = d.toLocaleString('ko-KR', { ...opts, timeZone: 'Asia/Tokyo' });
  const sg = d.toLocaleString('ko-KR', { ...opts, timeZone: 'Asia/Singapore' });
  const us = d.toLocaleString('ko-KR', { ...opts, timeZone: 'America/New_York' });
  return { th, jp, sg, us };
}

// 결과 요약용: 날짜·시각 분리, 태국·일본만 (수신일, 수신시각 TH/JP)
function formatDateAndTimeTHJP(isoString) {
  if (!isoString) return { date: '-', timeTh: '-', timeJp: '-' };
  const d = new Date(isoString);
  if (Number.isNaN(d.getTime())) return { date: '-', timeTh: '-', timeJp: '-' };
  const dateOpts = { year: 'numeric', month: '2-digit', day: '2-digit', timeZone: 'Asia/Bangkok' };
  const timeOpts = { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false };
  const date = d.toLocaleDateString('en-CA', dateOpts);
  const timeTh = d.toLocaleTimeString('en-CA', { ...timeOpts, timeZone: 'Asia/Bangkok' });
  const timeJp = d.toLocaleTimeString('en-CA', { ...timeOpts, timeZone: 'Asia/Tokyo' });
  return { date, timeTh, timeJp };
}

// DirectCredit용 CheckSum 생성 (매뉴얼 Table 1.3 + 제공 스크립트와 동일한 로직)
function generateDirectCreditCheckSum(payload, secretKey) {
  const parseVal = (val) => (val === null || val === undefined ? '' : String(val));

  const concatData =
    parseVal(payload.OrderNo) +
    parseVal(payload.CustomerId) +
    parseVal(payload.Amount) +
    parseVal(payload.PhoneNumber) +
    parseVal(payload.Description) +
    parseVal(payload.ChannelCode) +
    parseVal(payload.Currency) +
    parseVal(payload.LangCode) +
    parseVal(payload.RouteNo) +
    parseVal(payload.IPAddress) +
    parseVal(payload.TokenType) +
    parseVal(payload.CreditToken) +
    parseVal(payload.DirectCreditToken) +
    parseVal(payload.CreditMonth) +
    parseVal(payload.ShopID) +
    parseVal(payload.CustEmail) +
    parseVal(payload.SaveCard);

  const finalString = concatData + (secretKey ? secretKey.trim() : '');
  return crypto.createHash('md5').update(finalString, 'utf8').digest('hex');
}

// 전산(온더라인) 노티 수신 URL (환경변수로 설정, 없으면 전송 스킵)
const INTERNAL_NOTI_URL = process.env.INTERNAL_NOTI_URL || '';

// ========== ChillPay Transaction API (Request Void / Request Refund) ==========
const CHILLPAY_TRANSACTION_SANDBOX_BASE = 'https://sandbox-api-transaction.chillpay.co';
const CHILLPAY_TRANSACTION_PROD_BASE = 'https://api-transaction.chillpay.co';
const CHILLPAY_RECURRING_SANDBOX_BASE = 'https://sandbox-api-recurring.chillpay.co';
const CHILLPAY_RECURRING_PROD_BASE = 'https://api-recurring.chillpay.co';

function chillPayTransactionChecksum(concatStr, md5Key) {
  const s = (concatStr || '') + (md5Key ? String(md5Key).trim() : '');
  return crypto.createHash('md5').update(s, 'utf8').digest('hex').toLowerCase();
}

function chillPayRecurringChecksum(parts, merchantCode, apiKey, md5Key) {
  // Recurring 문서: 지정된 순서대로 값 concat 후 merchantCode + apiKey + MD5 Secret Key 붙여 MD5
  const p = Array.isArray(parts) ? parts : [];
  const concat = p.map((v) => (v == null ? '' : String(v))).join('')
    + String(merchantCode || '').trim()
    + String(apiKey || '').trim();
  return chillPayTransactionChecksum(concat, md5Key);
}

function getChillPayCredForEnv(env) {
  const cfg = loadChillPayTransactionConfig();
  const useSandbox = String(env || '').toLowerCase() === 'sandbox';
  const cred = useSandbox ? cfg.sandbox : cfg.production;
  return { useSandbox, cred };
}

async function chillPayRecurringRequest(env, pathSuffix, method, body, checksumParts, credOverride, baseUrlOverride) {
  const { useSandbox, cred: credFromSettings } = getChillPayCredForEnv(env);
  const cred = credOverride || credFromSettings;
  const pickedBase = useSandbox ? CHILLPAY_RECURRING_SANDBOX_BASE : CHILLPAY_RECURRING_PROD_BASE;
  const base = (baseUrlOverride && String(baseUrlOverride).trim())
    ? String(baseUrlOverride).trim().replace(/\/+$/, '')
    : pickedBase;
  if (!cred || !cred.mid || !cred.apiKey || !cred.md5) {
    return { success: false, error: 'ChillPay API 미설정 (mid/apiKey/md5)' };
  }
  const headers = {
    'Content-Type': 'application/json',
    'CHILLPAY-MerchantCode': cred.mid,
    // Recurring 문서/예제에서 ApiKey 헤더 표기가 혼재되어 있어 둘 다 보낸다.
    'CHILLPAY-ApiKey': cred.apiKey,
    'CHILLPAY-Apikey': cred.apiKey,
  };
  const hasChecksum = checksumParts !== null && checksumParts !== undefined;
  const checkSum = hasChecksum ? chillPayRecurringChecksum(checksumParts || [], cred.mid, cred.apiKey, cred.md5) : null;
  const payload = hasChecksum ? { ...(body || {}), check_sum: checkSum } : { ...(body || {}) };
  try {
    const res = await axios({
      url: base + pathSuffix,
      method: method || 'POST',
      headers,
      data: (method || 'POST').toUpperCase() === 'GET' ? undefined : payload,
      timeout: 20000,
    });
    const data = res.data;
    if (data && (data.status === 200 || data.status === '200')) return { success: true, data };
    return {
      success: false,
      error: (data && (data.message || data.Message)) || res.statusText || 'Recurring API 실패',
      data,
      debug: {
        env,
        useSandbox,
        url: base + pathSuffix,
        method: (method || 'POST').toUpperCase(),
        merchantCode: cred.mid,
        apiKey: maskChillPaySecret(cred.apiKey),
        hasChecksum,
      },
    };
  } catch (err) {
    const respData = err.response && err.response.data ? err.response.data : null;
    const msg = respData ? (respData.message || respData.Message || JSON.stringify(respData)) : err.message;
    return {
      success: false,
      error: msg,
      data: respData,
      debug: {
        env,
        useSandbox,
        url: base + pathSuffix,
        method: (method || 'POST').toUpperCase(),
        merchantCode: cred.mid,
        apiKey: maskChillPaySecret(cred.apiKey),
        hasChecksum,
      },
    };
  }
}

function getTestConfigEnvKey(cfgEnv) {
  const s = String(cfgEnv || '').toUpperCase().trim();
  if (s === 'SANDBOX') return 'sandbox';
  return 'production';
}

function getRecurringCredFromTestConfig(envKey, configId) {
  const id = String(configId || '').trim();
  const cfg = id ? TEST_CONFIGS.get(id) : null;
  if (!cfg) return { ok: false, error: '테스트 환경(config)을 선택하세요.' };
  const cfgEnvKey = getTestConfigEnvKey(cfg.environment);
  if (cfgEnvKey !== envKey) return { ok: false, error: '선택한 테스트 환경의 Environment가 현재 ENV와 다릅니다.' };
  const mid = String(cfg.merchantCode || '').trim();
  const apiKey = String(cfg.apiKey || '').trim();
  const md5 = String(cfg.md5Key || '').trim();
  const recurringApiUrl = String(cfg.recurringApiUrl || '').trim();
  if (!mid || !apiKey || !md5) return { ok: false, error: '선택한 테스트 환경에 MerchantCode/ApiKey/MD5Key가 없습니다.' };
  return { ok: true, cred: { mid, apiKey, md5 }, routeNo: String(cfg.routeNo || '').trim(), recurringApiUrl };
}

async function chillPayRequestVoid(transactionId, useSandbox) {
  const cfg = loadChillPayTransactionConfig();
  const cred = useSandbox ? cfg.sandbox : cfg.production;
  const base = useSandbox ? CHILLPAY_TRANSACTION_SANDBOX_BASE : CHILLPAY_TRANSACTION_PROD_BASE;
  if (!cred.mid || !cred.apiKey || !cred.md5) {
    return { success: false, error: 'ChillPay Transaction API 미설정 (mid/apiKey/md5)' };
  }
  const tid = String(transactionId).trim();
  if (!tid) return { success: false, error: 'TransactionId 없음' };
  const checksum = chillPayTransactionChecksum(tid, cred.md5);
  try {
    const res = await axios.post(
      base + '/api/v1/void/request',
      { TransactionId: Number(transactionId) || transactionId, Checksum: checksum },
      {
        headers: {
          'Content-Type': 'application/json',
          'CHILLPAY-MerchantCode': cred.mid,
          'CHILLPAY-ApiKey': cred.apiKey,
        },
        timeout: 15000,
      },
    );
    const data = res.data;
    if (data && (data.status === 200 || data.status === '200')) return { success: true, data: data.data || data };
    return { success: false, error: (data && data.message) || res.statusText || 'Void 요청 실패' };
  } catch (err) {
    const msg = err.response && err.response.data ? (err.response.data.message || JSON.stringify(err.response.data)) : err.message;
    return { success: false, error: msg };
  }
}

