  const escJs = (s) => String(s == null ? '' : s).replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/\r?\n/g, ' ');
  const remaining = Math.max(0, parseInt(String((req.query || {}).left || ''), 10) || 0);
