    if (rn) {
      for (const m of MERCHANTS.values()) {
        if (m && String(m.routeNo || '').trim() === rn) return m.name || m.label || m.merchantId || rn;
      }
    }
    // 2) TransactionId 기준 (노티 로그에서 merchantId 역추적)
