app.post('/admin/dev-internal-noti-settings', requireAuth, requirePage('dev_internal_noti_settings'), (req, res) => {
  const currency = (req.body.currency || '').trim();
  const pgSel = parseNotiSettingsPg(req);

  if (currency && CURRENCY_CODES.includes(currency)) {
    const full = loadDevInternalNotiSettingsFull(pgSel);
    let r = (req.body.rule || '=').trim() || '=';
    if (r !== 'X100' && r !== '/100') r = '=';
    full.amountRules[currency] = r;
    const rn = (req.body.routeNo || 'current').trim();
    full.routeNoMode[currency] = rn === 'delete' ? 'delete' : 'current';
    full.customerIdMode[currency] = normalizeDevCustomerIdModeForSave(req.body.customerId);
    const cn = (req.body.customerName || 'format').trim();
    full.customerNameMode[currency] = cn === 'none' ? 'none' : 'format';
    const mc = (req.body.merchantCode || 'off').trim();
    full.merchantCodeMode[currency] = mc === 'on' ? 'on' : 'off';
    full.original[currency] = req.body.original === 'on';
    saveDevInternalNotiSettings(full, pgSel);
    if (typeof appendConfigChangeLog === 'function') {
      appendConfigChangeLog({
        action: 'dev_internal_noti_settings',
        detail: `개발 노티 설정 변경 (통화 ${currency} 개별 저장)`,
        actor: req.session.adminUser || 'unknown',
        clientIp:
          (req.headers['x-forwarded-for'] || '').toString().split(',')[0].trim() ||
          req.ip ||
          '',
        payload: {
          currency,
          rule: req.body.rule,
          routeNo: req.body.routeNo,
          customerId: req.body.customerId,
          merchantCode: req.body.merchantCode,
          original: req.body.original,
        },
      });
    }
  } else {
    const amountRules = {};
    const routeNoMode = {};
    const customerIdMode = {};
    const customerNameMode = {};
    const merchantCodeMode = {};
    const original = {};
    CURRENCY_CODES.forEach((code) => {
      let r = (req.body['rule_' + code] || '=').trim() || '=';
      if (r !== 'X100' && r !== '/100') r = '=';
      amountRules[code] = r;
      const rn = (req.body['routeNo_' + code] || 'current').trim();
      routeNoMode[code] = rn === 'delete' ? 'delete' : 'current';
      customerIdMode[code] = normalizeDevCustomerIdModeForSave(req.body['customerId_' + code]);
      const cn = (req.body['customerName_' + code] || 'format').trim();
      customerNameMode[code] = cn === 'none' ? 'none' : 'format';
      const mc = (req.body['merchantCode_' + code] || 'off').trim();
      merchantCodeMode[code] = mc === 'on' ? 'on' : 'off';
      original[code] = req.body['original_' + code] === 'on';
    });
    saveDevInternalNotiSettings({
      amountRules,
      routeNoMode,
      customerIdMode,
      customerNameMode,
      merchantCodeMode,
      original,
    }, pgSel);
    if (typeof appendConfigChangeLog === 'function') {
      appendConfigChangeLog({
        action: 'dev_internal_noti_settings',
        detail: '개발 노티 설정 변경 (금액/RouteNo/CustomerId/MerchantCode/오리지널)',
        actor: req.session.adminUser || 'unknown',
        clientIp:
          (req.headers['x-forwarded-for'] || '').toString().split(',')[0].trim() ||
          req.ip ||
          '',
        payload: { amountRules, routeNoMode, customerIdMode, merchantCodeMode, original },
      });
    }
  }
  return res.redirect('/admin/dev-internal-noti-settings?pg=' + encodeURIComponent(pgSel));
});
