// 트래픽 분석 (일자별 / 월간별 / 시간별) — filterFn(hit) 가 false 이면 제외
function aggregateTrafficBuckets(filterFn) {
  const byDay = {};
  const byMonth = {};
  const byHour = {};
  const byDowHour = Array.from({ length: 7 }, () => Array(24).fill(0));
  let total = 0;
  for (let i = 0; i < TRAFFIC_HITS.length; i++) {
    const hit = TRAFFIC_HITS[i];
    if (filterFn && !filterFn(hit)) continue;
    total += 1;
    const d = new Date(hit.at);
    if (Number.isNaN(d.getTime())) continue;
    const dayKey = d.toISOString().slice(0, 10);
    const monthKey = d.toISOString().slice(0, 7);
    const hourKey = d.getUTCHours();
    const dow = d.getUTCDay();
    byDay[dayKey] = (byDay[dayKey] || 0) + 1;
    byMonth[monthKey] = (byMonth[monthKey] || 0) + 1;
    byHour[hourKey] = (byHour[hourKey] || 0) + 1;
    byDowHour[dow][hourKey] = (byDowHour[dow][hourKey] || 0) + 1;
  }
  const dayEntries = Object.entries(byDay).sort((a, b) => b[0].localeCompare(a[0])).slice(0, 31);
  const monthEntries = Object.entries(byMonth).sort((a, b) => b[0].localeCompare(a[0])).slice(0, 12);
  const hourEntries = Array.from({ length: 24 }, (_, h) => [h, byHour[h] || 0]);
  const maxDay = Math.max(1, ...dayEntries.map((e) => e[1]));
  const maxMaxMonth = Math.max(1, ...monthEntries.map((e) => e[1]));
  const maxHour = Math.max(1, ...hourEntries.map((e) => e[1]));
  let maxHeat = 0;
  for (let di = 0; di < 7; di++) {
    for (let h = 0; h < 24; h++) {
      if (byDowHour[di][h] > maxHeat) maxHeat = byDowHour[di][h];
    }
  }
  return {
    dayEntries,
    monthEntries,
    hourEntries,
    maxDay,
    maxMonth: maxMaxMonth,
    maxHour,
    byDowHour,
    maxHeat,
    total,
  };
}

function trafficEntriesToMap(entries) {
  const m = {};
  if (!entries) return m;
  for (let i = 0; i < entries.length; i++) {
    m[entries[i][0]] = entries[i][1];
  }
  return m;
}

/** PG 노티 로그 메모리 보관분: 결제 성공 건 기준 금액 통계 — ICOPAY 전용 금액 규칙 파일 기준(노티 환경설정과 별도) */
function isSuccessPaymentForTrafficStats(body) {
  if (!body || typeof body !== 'object') return false;
  const ps = body.PaymentStatus ?? body.paymentStatus ?? body.status;
  if (ps === 0 || ps === '0' || ps === 1 || ps === '1') return true;
  if (typeof ps === 'string') {
    const lower = ps.toLowerCase();
    if (lower === 'success' || lower === 'complete') return true;
  }
  return false;
}

/** 노티 본문 Amount·Currency → ICOPAY (ICOPAY 전용 통화별 규칙 · PG별, applyAmountRule) */
function notiBodyAmountToIcopay(body, pgKey) {
  if (!body || typeof body !== 'object') return null;
  const pg = pgKey === 'jpay' ? 'jpay' : 'chillpay';
  const amountRaw = getNotiBodyAmountRawForIcopay(body, pg);
  if (amountRaw == null || amountRaw === '') return null;
  const v = computeIcopayAmount(amountRaw, body.Currency ?? body.currency, pg);
  if (!Number.isFinite(v) || v <= 0) return null;
  return v;
}

function aggregatePaymentStatsFromNotiLogs() {
  const logs = Array.isArray(NOTI_LOGS) ? NOTI_LOGS : [];
  const acc = {
    all: { sum: 0, count: 0, max: 0, days: new Set() },
    chillpay: { sum: 0, count: 0, max: 0, days: new Set() },
    jpay: { sum: 0, count: 0, max: 0, days: new Set() },
  };
  for (let i = 0; i < logs.length; i++) {
    const log = logs[i];
    const body = parseNotiBody(log);
    if (!isSuccessPaymentForTrafficStats(body)) continue;
    const pg = getNotiLogPgAcquirer(log) === 'jpay' ? 'jpay' : 'chillpay';
    const icopay = notiBodyAmountToIcopay(body, pg);
    if (icopay == null) continue;
    const ymd = getBangkokYmdFromIso(log.receivedAtIso || log.receivedAt);
    const keys = ['all', pg];
    for (let k = 0; k < keys.length; k++) {
      const key = keys[k];
      const b = acc[key];
      b.sum += icopay;
      b.count += 1;
      if (icopay > b.max) b.max = icopay;
      if (ymd) b.days.add(ymd);
    }
  }
  const finish = (b) => {
    const dayCount = b.days.size;
    const avgDaily = dayCount > 0 ? b.sum / dayCount : 0;
    return { sum: b.sum, count: b.count, max: b.max, avgDaily, dayCount };
  };
  return {
    all: finish(acc.all),
    chillpay: finish(acc.chillpay),
    jpay: finish(acc.jpay),
  };
}

function formatMonitorBytes(n) {
  const x = Number(n) || 0;
  if (x >= 1073741824) return (x / 1073741824).toFixed(3) + ' GB';
  if (x >= 1048576) return (x / 1048576).toFixed(2) + ' MB';
  if (x >= 1024) return (x / 1024).toFixed(1) + ' KB';
  return String(Math.round(x)) + ' B';
}

/** data/ 등 디렉터리 전체 파일 크기 합산 (심볼릭 링크는 건너뜀) */
function sumDirectoryBytesSync(rootDir) {
  let total = 0;
  const stack = [path.resolve(rootDir)];
  while (stack.length) {
    const d = stack.pop();
    let entries;
    try {
      entries = fs.readdirSync(d, { withFileTypes: true });
    } catch {
      continue;
    }
    for (let i = 0; i < entries.length; i++) {
      const e = entries[i];
      const name = e && e.name;
      if (!name || name === '.' || name === '..') continue;
      const p = path.join(d, name);
      try {
        if (e.isSymbolicLink()) continue;
        if (e.isDirectory()) stack.push(p);
        else if (e.isFile()) total += fs.statSync(p).size;
      } catch {
        /* skip */
      }
    }
  }
  return total;
}

function getDiskUsageWin32ForPath(basePath) {
  const root = path.parse(path.resolve(basePath)).root;
  const letterM = /^([a-zA-Z]):/i.exec(root.replace(/\\/g, '/'));
  const letter = letterM ? letterM[1].toUpperCase() : null;
  if (!letter) return null;
  try {
    const { execFileSync } = require('child_process');
    const ps = `$d = Get-PSDrive -Name '${letter}' -PSProvider FileSystem -ErrorAction SilentlyContinue; if ($null -eq $d) { exit 1 }; [string]($d.Used) + ' ' + [string]($d.Free)`;
    const out = String(
      execFileSync('powershell.exe', ['-NoProfile', '-NonInteractive', '-ExecutionPolicy', 'Bypass', '-Command', ps], {
        encoding: 'utf8',
        timeout: 8000,
        windowsHide: true,
        maxBuffer: 1024 * 1024,
      }),
    ).trim();
    const parts = out.split(/\s+/);
    if (parts.length < 2) return null;
    const used = Number(parts[0]);
    const free = Number(parts[1]);
    if (!Number.isFinite(used) || !Number.isFinite(free)) return null;
    const total = used + free;
    if (total <= 0) return null;
    return { total, used, free, pct: (used / total) * 100 };
  } catch {
    return null;
  }
}

/** data/ 가 올라간 디스크 볼륨의 사용량 (가능 시). Linux 등: fs.statfsSync, Windows: PowerShell 보조 */
function getHostDiskUsageNearPath(basePath) {
  const resolved = path.resolve(basePath);
  try {
    if (typeof fs.statfsSync === 'function') {
      const s = fs.statfsSync(resolved);
      const bsize = Number(s.bsize) || Number(s.frsize) || 512;
      const blocks = Number(s.blocks);
      const bavailRaw = s.bavail != null ? s.bavail : s.bfree;
      const bavail = Number(bavailRaw);
      if (Number.isFinite(blocks) && Number.isFinite(bsize) && blocks > 0) {
        const total = blocks * bsize;
        const avail = Number.isFinite(bavail) ? bavail * bsize : 0;
        const used = Math.max(0, total - avail);
        const pct = total > 0 ? (used / total) * 100 : 0;
        return { total, used, free: avail, pct };
      }
    }
  } catch {
    /* fall through */
  }
  if (process.platform === 'win32') return getDiskUsageWin32ForPath(resolved);
  return null;
}

/** 서버 모니터 카드·로그인 후 건강 경고에 공통 (임계치 단일화) */
const MONITOR_HOST_HEALTH = {
  SYS_MEM_PCT: 90,
  HEAP_FRAC: 0.92,
  /** heapTotal이 이보다 작으면 비율(92%)만으로는 위험 처리하지 않음 — 기동 직후 V8이 작은 힙만 잡으면 20MB대도 90%대가 되어 오탐이 난다 */
  HEAP_FRAC_MIN_TOTAL_BYTES: 64 * 1024 * 1024,
  HEAP_BYTES: 1073741824,
  RSS_FRAC_OF_SYS: 0.5,
  RSS_BYTES: 1610612736,
  LOAD_MULT: 2,
  DATA_DIR_BYTES: 1073741824,
  DISK_PCT: 90,
};

function getSystemHealthMonitorMetrics(locale) {
  const H = MONITOR_HOST_HEALTH;
  const totalM = os.totalmem();
  const freeM = os.freemem();
  const usedM = totalM - freeM;
  const sysMemPct = totalM ? ((usedM / totalM) * 100).toFixed(1) : '0';
  const pm = process.memoryUsage();
  const la = os.loadavg();
  const loadStr =
    process.platform === 'win32'
      ? '—'
      : [(la[0] || 0).toFixed(2), (la[1] || 0).toFixed(2), (la[2] || 0).toFixed(2)].join(' / ');
  const dataDirBytes = sumDirectoryBytesSync(DATA_DIR);
  const diskUsage = getHostDiskUsageNearPath(DATA_DIR);
  const diskPctStr = diskUsage && Number.isFinite(diskUsage.pct) ? diskUsage.pct.toFixed(1) : null;
  const cpuN = Math.max(1, (os.cpus() && os.cpus().length) || 1);
  const sysMemNum = totalM > 0 ? (usedM / totalM) * 100 : 0;
  const diskBarClass =
    diskUsage && Number.isFinite(diskUsage.pct)
      ? diskUsage.pct >= H.DISK_PCT
        ? ' danger'
        : diskUsage.pct >= 80
          ? ' warn'
          : ''
      : '';
  const diskBarW =
    diskUsage && Number.isFinite(diskUsage.pct) ? String(Math.min(100, Math.max(0, diskUsage.pct))) : '0';
  const dangerSysMem = sysMemNum >= H.SYS_MEM_PCT;
  const heapRatioDanger =
    pm.heapTotal >= H.HEAP_FRAC_MIN_TOTAL_BYTES
    && pm.heapUsed / pm.heapTotal >= H.HEAP_FRAC;
  const dangerHeap = pm.heapTotal > 0 && (heapRatioDanger || pm.heapUsed >= H.HEAP_BYTES);
  const dangerRss =
    totalM > 0
    && (pm.rss >= totalM * H.RSS_FRAC_OF_SYS || pm.rss >= H.RSS_BYTES);
  const dangerLoad =
    process.platform !== 'win32' && (la[0] || 0) > cpuN * H.LOAD_MULT;
  const dangerDataDir = dataDirBytes >= H.DATA_DIR_BYTES;
  const dangerDisk = diskUsage && Number.isFinite(diskUsage.pct) && diskUsage.pct >= H.DISK_PCT;
  const healthAlertMessages = [];
  if (dangerSysMem) healthAlertMessages.push(t(locale, 'health_alert_sys_mem'));
  if (dangerHeap) healthAlertMessages.push(t(locale, 'health_alert_node_heap'));
  if (dangerRss) healthAlertMessages.push(t(locale, 'health_alert_node_rss'));
  if (dangerLoad) healthAlertMessages.push(t(locale, 'health_alert_load'));
  if (dangerDataDir) healthAlertMessages.push(t(locale, 'health_alert_data_dir'));
  if (dangerDisk) healthAlertMessages.push(t(locale, 'health_alert_disk'));
  return {
    totalM,
    freeM,
    usedM,
    sysMemPct,
    pm,
    la,
    loadStr,
    dataDirBytes,
    diskUsage,
    diskPctStr,
    cpuN,
    sysMemNum,
    diskBarClass,
    diskBarW,
    dangerSysMem,
    dangerHeap,
    dangerRss,
    dangerLoad,
    dangerDataDir,
    dangerDisk,
    healthAlertMessages,
  };
}

function memberHasAdvancedSystemMonitor(member) {
  return !!(member && Array.isArray(member.permissions) && member.permissions.includes('advanced_system_monitor'));
}

/** 로그인·비밀번호 변경·OTP 등록 직후 기본 진입 URL (역할·슈퍼 admin·서버 헬스 알림 반영) */
function getPostAuthHomeRedirectUrl(req, sessionMember, permissions) {
  const perms = Array.isArray(permissions) ? permissions : [];
  if (!sessionMember) return getFirstAllowedRedirectUrl(perms);

  const role = sessionMember.role;
  const uid = sessionMember.userId || '';

  if (role === ROLES.SUPER_ADMIN && uid === 'admin') {
    if (req.session.healthAlertPending && memberHasAdvancedSystemMonitor(sessionMember)) {
      return PAGE_KEY_TO_DEFAULT_URL.advanced_system_monitor || '/admin/system-monitor';
    }
    if (perms.includes('cr_transactions') || perms.includes('cancel_refund')) {
      return PAGE_KEY_TO_DEFAULT_URL.cr_transactions || '/admin/transactions';
    }
    return getFirstAllowedRedirectUrl(perms);
  }

  if (role === ROLES.ADMIN) {
    return '/admin/pg-transactions?sort=today';
  }

  if (role === ROLES.OPERATOR) {
    if (perms.includes('cr_pg_transactions') || perms.includes('cancel_refund')) {
      return '/admin/pg-transactions?sort=today';
    }
    return getFirstAllowedRedirectUrl(perms);
  }

  return getFirstAllowedRedirectUrl(perms);
}

function syncSessionHealthAlertPending(req, locale) {
  if (!req || !req.session) return;
  if (!memberHasAdvancedSystemMonitor(req.session.member)) {
    req.session.healthAlertPending = false;
    return;
  }
  const { healthAlertMessages } = getSystemHealthMonitorMetrics(locale);
  req.session.healthAlertPending = healthAlertMessages.length > 0;
}

function buildAdminHealthAlertModalHtml(locale, messages) {
  const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  const items = messages.map((m) => `<li style="margin:6px 0;line-height:1.45;">${esc(m)}</li>`).join('');
  return `
<div id="admin-health-alert-overlay" style="position:fixed;inset:0;background:rgba(17,24,39,0.55);z-index:99999;display:flex;align-items:center;justify-content:center;padding:20px;box-sizing:border-box;">
  <div role="dialog" aria-modal="true" aria-labelledby="admin-health-alert-title" style="background:#fff;max-width:480px;width:100%;border-radius:12px;border:1px solid #fecaca;box-shadow:0 20px 50px rgba(0,0,0,0.2);padding:22px 24px;box-sizing:border-box;">
    <h2 id="admin-health-alert-title" style="margin:0 0 10px;font-size:1.15rem;color:#991b1b;">${esc(t(locale, 'health_alert_modal_title'))}</h2>
    <p style="margin:0 0 12px;font-size:13px;color:#374151;line-height:1.5;">${esc(t(locale, 'health_alert_modal_intro'))}</p>
    <ul style="margin:0 0 18px;padding-left:20px;font-size:13px;color:#1f2937;">${items}</ul>
    <button type="button" id="admin-health-alert-ok" style="width:100%;padding:12px 16px;border:none;border-radius:8px;background:#b91c1c;color:#fff;font-size:14px;font-weight:600;cursor:pointer;">${esc(t(locale, 'health_alert_modal_confirm'))}</button>
  </div>
</div>
<script>
(function(){
  var o = document.getElementById('admin-health-alert-overlay');
  var b = document.getElementById('admin-health-alert-ok');
  if (!o || !b) return;
  b.addEventListener('click', function(){ window.location.href = '/admin/system-monitor'; });
})();
</script>`;
}

function buildServerSituationAnalysisRecord(locale, adminUser) {
  const state = getSystemMonitorState();
  const agg = buildSystemMonitorAggregates(state);
  const quotaBytes = getEffectiveMonthlyQuotaBytes();
  const quotaGb = getEffectiveMonthlyQuotaGb();
  const quotaUsedPct = quotaBytes > 0 ? Math.min(100, (agg.monthBytes / quotaBytes) * 100) : 0;
  const m = getSystemHealthMonitorMetrics(locale);
  let maxSev = 0;
  const bump = (status) => {
    const s = status === 'danger' ? 2 : status === 'warn' ? 1 : 0;
    if (s > maxSev) maxSev = s;
  };
  const row = (id, valueStr, status) => {
    bump(status);
    return {
      id,
      label: t(locale, 'monitor_situation_item_' + id),
      value: valueStr,
      status,
      note: t(locale, 'monitor_situation_note_' + id),
    };
  };
  const rows = [];
  rows.push(row('runtime', `${process.version} · ${process.platform}`, 'ok'));
  const sm = m.dangerSysMem ? 'danger' : m.sysMemNum >= 70 ? 'warn' : 'ok';
  rows.push(row('sys_mem', `${m.sysMemPct}% (${formatMonitorBytes(m.usedM)} / ${formatMonitorBytes(m.totalM)})`, sm));
  const heapRatio = m.pm.heapTotal > 0 ? Math.round((m.pm.heapUsed / m.pm.heapTotal) * 100) : 0;
  rows.push(row('node_heap', `${formatMonitorBytes(m.pm.heapUsed)} / ${formatMonitorBytes(m.pm.heapTotal)} (${heapRatio}%)`, m.dangerHeap ? 'danger' : 'ok'));
  rows.push(row('node_rss', formatMonitorBytes(m.pm.rss), m.dangerRss ? 'danger' : 'ok'));
  rows.push(row('load_avg', m.loadStr, m.dangerLoad ? 'danger' : 'ok'));
  rows.push(row('uptime', formatMonitorUptime(process.uptime()), 'ok'));
  rows.push(row('data_dir', formatMonitorBytes(m.dataDirBytes), m.dangerDataDir ? 'danger' : 'ok'));
  let diskStat = 'ok';
  let diskVal = '—';
  if (m.diskUsage && Number.isFinite(m.diskUsage.pct)) {
    diskVal = `${m.diskPctStr}% (${formatMonitorBytes(m.diskUsage.used)} / ${formatMonitorBytes(m.diskUsage.total)})`;
    diskStat = m.dangerDisk ? 'danger' : m.diskUsage.pct >= 75 ? 'warn' : 'ok';
  }
  rows.push(row('disk', diskVal, diskStat));
  const tq = quotaUsedPct >= 95 ? 'danger' : quotaUsedPct >= 80 ? 'warn' : 'ok';
  rows.push(row('traffic_quota', `${formatMonitorBytes(agg.monthBytes)} (${(agg.monthBytes / 1073741824).toFixed(3)} GB) · ${quotaUsedPct.toFixed(1)}% / ${quotaGb} GB`, tq));
  const summary = maxSev === 2 ? t(locale, 'monitor_situation_summary_danger') : maxSev === 1 ? t(locale, 'monitor_situation_summary_warn') : t(locale, 'monitor_situation_summary_ok');
  return {
    atIso: new Date().toISOString(),
    adminUser: adminUser || '—',
    summary,
    rows,
  };
}

function renderServerSituationAnalysesSection(locale, store, esc, situationFlash) {
  const flash = situationFlash
    ? `<div class="mon-quota-flash ok" role="status">${esc(t(locale, 'monitor_situation_saved'))}</div>`
    : '';
  const items = store.items || [];
  const blocks = items.map((rec) => {
    const tbody = (rec.rows || []).map((r) => {
      const st = r.status === 'danger' ? 'danger' : r.status === 'warn' ? 'warn' : 'ok';
      const badgeKey = st === 'danger' ? 'monitor_situation_status_danger' : st === 'warn' ? 'monitor_situation_status_warn' : 'monitor_situation_status_ok';
      const cls = st === 'danger' ? 'sit-bad' : st === 'warn' ? 'sit-warn' : 'sit-ok';
      return `<tr><td>${esc(r.label)}</td><td>${esc(r.value)}</td><td><span class="sit-badge ${cls}">${esc(t(locale, badgeKey))}</span></td><td>${esc(r.note)}</td></tr>`;
    }).join('');
    const metaRaw = t(locale, 'monitor_situation_record_meta')
      .replace(/\{\{date\}\}/g, rec.atIso || '')
      .replace(/\{\{user\}\}/g, rec.adminUser || '—');
    return `<div class="mon-situation-one">
      <div class="mon-situation-meta">${esc(metaRaw)}</div>
      <p class="mon-situation-summary">${esc(rec.summary || '')}</p>
      <table class="mon-situation-table">
        <thead><tr>
          <th>${esc(t(locale, 'monitor_situation_th_item'))}</th>
          <th>${esc(t(locale, 'monitor_situation_th_value'))}</th>
          <th>${esc(t(locale, 'monitor_situation_th_status'))}</th>
          <th>${esc(t(locale, 'monitor_situation_th_note'))}</th>
        </tr></thead>
        <tbody>${tbody}</tbody>
      </table>
    </div>`;
  }).join('');
  const emptyNote = items.length === 0 ? `<p class="mon-situation-empty">${esc(t(locale, 'monitor_situation_empty'))}</p>` : '';
  return `<div class="mon-situation-wrap">
    <h2 class="mon-situation-h2">${esc(t(locale, 'monitor_situation_title'))}</h2>
    <p class="admin-page-desc mon-situation-intro">${esc(t(locale, 'monitor_situation_intro'))}</p>
    ${flash}
    <form method="post" action="/admin/system-monitor/situation-analyze" class="mon-situation-form">
      <button type="submit" class="mon-situation-run-btn">${esc(t(locale, 'monitor_situation_run'))}</button>
    </form>
    <h3 class="mon-situation-history-title">${esc(t(locale, 'monitor_situation_history'))}</h3>
    ${blocks}
    ${emptyNote}
  </div>`;
}

function formatMonitorUptime(sec) {
  const s = Math.max(0, Math.floor(Number(sec) || 0));
  const d = Math.floor(s / 86400);
  const h = Math.floor((s % 86400) / 3600);
  const m = Math.floor((s % 3600) / 60);
  return d + 'd ' + h + 'h ' + m + 'm';
}

function truncateMonitorText(str, maxLen) {
  const t = String(str || '').replace(/\r/g, '');
  if (t.length <= maxLen) return t;
  return t.slice(0, maxLen) + '…';
}

// ===== SSL 인증서 (Let's Encrypt 등 PEM fullchain/leaf) 모니터링 · 선택적 갱신 명령 =====
const sslMonitorRuntime = { state: null };

/**
 * DEPLOY.md 기준 스택: Nginx + certbot --nginx → PEM은 보통 /etc/letsencrypt/live/<도메인>/fullchain.pem
 * 환경변수가 비어 있을 때만 사용. MONITOR_SSL_LE_DOMAIN 으로 도메인 고정 가능(다중 인증서 서버).
 */
function resolveLetsEncryptLiveFullchainFallback() {
  if (process.platform === 'win32') return '';
  const liveRoot = '/etc/letsencrypt/live';
  try {
    if (!fs.existsSync(liveRoot) || !fs.statSync(liveRoot).isDirectory()) return '';
  } catch {
    return '';
  }
  const explicit = String(process.env.MONITOR_SSL_LE_DOMAIN || '').trim();
  if (explicit) {
    const p = path.join(liveRoot, explicit, 'fullchain.pem');
    try {
      if (fs.existsSync(p) && fs.statSync(p).isFile()) return p;
    } catch {
      return '';
    }
    return '';
  }
  let names;
  try {
    names = fs.readdirSync(liveRoot, { withFileTypes: true });
  } catch {
    return '';
  }
  const dirs = names.filter((d) => d.isDirectory() && d.name !== 'README').map((d) => d.name);
  const withPem = dirs.filter((name) => {
    try {
      const fp = path.join(liveRoot, name, 'fullchain.pem');
      return fs.existsSync(fp) && fs.statSync(fp).isFile();
    } catch {
      return false;
    }
  });
  if (withPem.length === 1) return path.join(liveRoot, withPem[0], 'fullchain.pem');
  return '';
}

function resolveMonitorSslCertPathMeta() {
  const a = String(process.env.MONITOR_SSL_CERT_PATH || '').trim();
  const b = String(process.env.SSL_CERTIFICATE_FILE || process.env.NGINX_SSL_CERT || '').trim();
  const c = String(process.env.LETSENCRYPT_FULLCHAIN_PATH || '').trim();
  const p = a || b || c;
  if (p) return { path: path.resolve(p), source: 'env' };
  const le = resolveLetsEncryptLiveFullchainFallback();
  if (le) return { path: path.resolve(le), source: 'letsencrypt_auto' };
  return { path: '', source: 'none' };
}

function resolveMonitorSslCertPath() {
  return resolveMonitorSslCertPathMeta().path;
}

function sslRenewCommandConfigured() {
  return String(process.env.MONITOR_SSL_RENEW_CMD || '').trim();
}

function sslAutoRenewEnabled() {
  return String(process.env.MONITOR_SSL_AUTO_RENEW_ENABLED || '') === '1' && !!sslRenewCommandConfigured();
}

function extractFirstPemCertificateBlock(pemText) {
  const m = /-----BEGIN CERTIFICATE-----[\r\n]+([\s\S]*?)[\r\n]+-----END CERTIFICATE-----/.exec(pemText || '');
  if (!m) return null;
  const body = m[1].replace(/\r\n/g, '\n').trim();
  return `-----BEGIN CERTIFICATE-----\n${body}\n-----END CERTIFICATE-----\n`;
}

function readLeafCertificateInfo(certPath) {
  try {
    if (!certPath || !fs.existsSync(certPath)) return { ok: false, error: 'missing_file' };
    const raw = fs.readFileSync(certPath, 'utf8');
    const block = extractFirstPemCertificateBlock(raw);
    if (!block) return { ok: false, error: 'no_pem' };
    const cert = new crypto.X509Certificate(block);
    const notBefore = new Date(cert.validFrom);
    const notAfter = new Date(cert.validTo);
    if (Number.isNaN(notBefore.getTime()) || Number.isNaN(notAfter.getTime())) return { ok: false, error: 'bad_dates' };
    const now = Date.now();
    const daysRemaining = Math.floor((notAfter.getTime() - now) / 86400000);
    return {
      ok: true,
      subject: cert.subject,
      issuer: cert.issuer,
      fingerprint256: cert.fingerprint256,
      serialNumber: cert.serialNumber,
      validFromMs: notBefore.getTime(),
      validToMs: notAfter.getTime(),
      validFromIso: notBefore.toISOString(),
      validToIso: notAfter.toISOString(),
      daysRemaining,
    };
  } catch (e) {
    return { ok: false, error: e.message || 'parse_error' };
  }
}

function loadSslMonitorState() {
  try {
    const raw = fs.readFileSync(SSL_MONITOR_STATE_PATH, 'utf8');
    const o = JSON.parse(raw);
    if (!o || typeof o !== 'object') throw new Error('bad');
    return o;
  } catch {
    return {
      v: 1,
      previousNotAfterMs: null,
      previousNotAfterIso: null,
      lastRenewalDetectedAtIso: null,
      lastCheckAtIso: null,
      lastVerifiedNotAfterIso: null,
      lastRenewAttemptAtIso: null,
      lastRenewAttemptOk: null,
      lastRenewAttemptExitCode: null,
      lastRenewAttemptMessage: '',
      lastCertFingerprint256: null,
      renewalVerifiedAfterAttempt: null,
    };
  }
}

function getSslMonitorState() {
  if (!sslMonitorRuntime.state) sslMonitorRuntime.state = loadSslMonitorState();
  return sslMonitorRuntime.state;
}

function saveSslMonitorStateNow() {
  const s = sslMonitorRuntime.state;
  if (!s) return;
  try {
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    fs.writeFileSync(SSL_MONITOR_STATE_PATH, JSON.stringify(s), 'utf8');
  } catch (e) {
    console.error('[ssl-monitor] save failed', e.message);
  }
}

function applySslCertificateReadToState(info) {
  if (!info || !info.ok) return;
  const st = getSslMonitorState();
  const prev = st.previousNotAfterMs;
  if (prev != null && info.validToMs > prev) {
    st.lastRenewalDetectedAtIso = new Date().toISOString();
  }
  st.previousNotAfterMs = info.validToMs;
  st.previousNotAfterIso = info.validToIso;
  st.lastCheckAtIso = new Date().toISOString();
  st.lastVerifiedNotAfterIso = info.validToIso;
  st.lastCertFingerprint256 = info.fingerprint256 || null;
  saveSslMonitorStateNow();
}

function sslRenewDaysBefore() {
  const n = Number(process.env.MONITOR_SSL_RENEW_DAYS_BEFORE);
  return Number.isFinite(n) && n >= 1 ? Math.min(89, Math.floor(n)) : 30;
}

function sslRenewCooldownMs() {
  const h = Number(process.env.MONITOR_SSL_RENEW_COOLDOWN_HOURS);
  const hrs = Number.isFinite(h) && h >= 1 ? Math.min(168, h) : 22;
  return hrs * 3600000;
}

/** 갱신 명령 실행 전후 PEM을 읽어 만료일이 연장되었는지 검증 */
function runSslRenewShellSync(reason, actor, reqForLog) {
  const cmd = sslRenewCommandConfigured();
  if (!cmd) return { ok: false, renewalVerified: false, exitCode: -1, message: 'no_cmd' };
  const certPath = resolveMonitorSslCertPath();
  const before = readLeafCertificateInfo(certPath);
  const beforeMs = before.ok ? before.validToMs : null;
  const { execSync } = require('child_process');
  let stdout = '';
  let stderr = '';
  let exitCode = 0;
  try {
    stdout = String(
      execSync(cmd, {
        encoding: 'utf8',
        timeout: 300000,
        maxBuffer: 4 * 1024 * 1024,
        windowsHide: true,
        shell: true,
      }),
    );
  } catch (e) {
    stdout = String(e.stdout || '');
    stderr = String(e.stderr || e.message || '');
    exitCode = typeof e.status === 'number' ? e.status : 1;
  }
  const after = readLeafCertificateInfo(certPath);
  const renewalVerified = beforeMs != null && after.ok && after.validToMs > beforeMs;
  const msg = truncateMonitorText(`${stdout}\n${stderr}`, 4000);
  const st = getSslMonitorState();
  st.lastRenewAttemptAtIso = new Date().toISOString();
  st.lastRenewAttemptOk = exitCode === 0;
  st.lastRenewAttemptExitCode = exitCode;
  st.lastRenewAttemptMessage = msg;
  st.renewalVerifiedAfterAttempt = renewalVerified;
  if (renewalVerified) {
    st.lastRenewalDetectedAtIso = st.lastRenewAttemptAtIso;
    st.previousNotAfterMs = after.validToMs;
    st.previousNotAfterIso = after.validToIso;
    st.lastVerifiedNotAfterIso = after.validToIso;
    st.lastCertFingerprint256 = after.fingerprint256 || null;
  }
  if (after.ok) applySslCertificateReadToState(after);
  else saveSslMonitorStateNow();
  const clientIp = reqForLog
    ? (reqForLog.headers['x-forwarded-for'] || '').toString().split(',')[0].trim() || reqForLog.ip || ''
    : '';
  appendConfigChangeLog({
    action: 'ssl_renew_attempt',
    detail: 'SSL 갱신 명령 실행',
    actor: actor || 'system',
    clientIp,
    payload: { reason, exitCode, renewalVerified, ok: exitCode === 0 },
  });
  return { ok: exitCode === 0, exitCode, renewalVerified, message: msg };
}

function performSslMonitorScheduledTick() {
  const certPath = resolveMonitorSslCertPath();
  if (!certPath || !fs.existsSync(certPath)) return;
  const info = readLeafCertificateInfo(certPath);
  if (info.ok) applySslCertificateReadToState(info);
  if (!sslAutoRenewEnabled()) return;
  if (!info.ok || info.daysRemaining == null) return;
  if (info.daysRemaining > sslRenewDaysBefore()) return;
  const st = getSslMonitorState();
  const last = st.lastRenewAttemptAtIso ? Date.parse(st.lastRenewAttemptAtIso) : 0;
  if (Date.now() - last < sslRenewCooldownMs()) return;
  runSslRenewShellSync('scheduled', 'system', null);
}

setInterval(performSslMonitorScheduledTick, 60 * 60 * 1000);
setTimeout(performSslMonitorScheduledTick, 20000);

